parameters.jsCode:
const response = $input.item.json;
const notionPage = $('Notion — Pages à générer').item.json;

const rawText = response.content?.[0]?.text ?? '';

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch {
  // Tente d'extraire le JSON si Claude a ajouté du texte autour
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    throw new Error('Réponse Claude non parseable : ' + rawText);
  }
}

return {
  json: {
    pageId: notionPage.id,
    titre: (parsed.titre ?? '').slice(0, 200),
    description: parsed.description ?? '',
    corrections: Array.isArray(parsed.corrections) ? parsed.corrections.join('\n') : '',
    tags: Array.isArray(parsed.tags) ? parsed.tags : [],
  }
};
